sql:
SELECT airline_name, iata_code 
FROM airlines 
WHERE airline_id = (SELECT airline_id FROM flights WHERE flight_id = 1);

SELECT flight_number, status, estimated_flight_duration
FROM flights
WHERE estimated_flight_duration = (
  SELECT MAX(estimated_flight_duration) 
  FROM flights
);

external_knowledge:
- Upcoming flights refer to flights with a departure time later than the current time; 
- Delayed or cancelled flights are those with a status of 'Delayed' or 'Cancelled'; 
- Email notifications are a type of notification sent to the recipient's email address.

sql:
SELECT f.flight_id, f.departure_time, a.airport_id, a.iata_code, a.airport_name
FROM flights AS f
JOIN airports AS a ON f.departure_airport = a.iata_code;

SELECT f.status, f.departure_time, a.airline_name
FROM flights f
JOIN airlines a ON f.airline_id = a.airline_id;
